module RefModule (  
    input clk,  
    input reset,  
    input enable,  
    output reg [2:0] active_channel  
);  

    reg [2:0] unused_channel;  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            unused_channel <= 3'b000;  
            active_channel <= 3'b000;  
        end else if (enable) begin  
            if (unused_channel < 3'b111)  
                unused_channel <= unused_channel + 1;  
            else  
                unused_channel <= 3'b000;  
            active_channel <= unused_channel;  
        end  
    end  
endmodule
